const TEAM_IMAGES = {
  'atletico-mg': 'data:image/png;base64,',
  'athletico': 'data:image/png;base64,',
  'bahia': 'data:image/png;base64,',
  'botafogo': 'data:image/png;base64,',
  'bragantino': 'data:image/png;base64,',
  'chapecoense': 'data:image/png;base64,',
  'corinthians': 'data:image/png;base64,',
  'coritiba': 'data:image/png;base64,',
  'cruzeiro': 'data:image/png;base64,',
  'flamengo': 'data:image/png;base64,',
  'fluminense': 'data:image/png;base64,',
  'gremio': 'data:image/png;base64,',
  'internacional': 'data:image/png;base64,',
  'mirassol': 'data:image/png;base64,',
  'palmeiras': 'data:image/png;base64,',
  'remo': 'data:image/png;base64,',
  'santos': 'data:image/png;base64,',
  'sao-paulo': 'data:image/png;base64,',
  'vasco': 'data:image/png;base64,',
  'vitoria': 'data:image/png;base64,',
};

function teamKey(name) {
  const raw = String(name || "").toLowerCase();
  const clean = raw.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]+/g, "-");
  if (clean.includes("athletico")) return "athletico";
  if ((clean.includes("atletico") || clean.includes("tico")) && clean.includes("mg")) return "atletico-mg";
  if (clean.includes("sao") && clean.includes("paulo")) return "sao-paulo";
  if (clean.includes("paulo")) return "sao-paulo";
  if (clean.includes("gremio") || clean.includes("mio")) return "gremio";
  if (clean.includes("vitoria") || clean.includes("ria")) return "vitoria";
  if (clean.includes("bragantino")) return "bragantino";
  if (clean.includes("chapecoense")) return "chapecoense";
  if (clean.includes("corinthians")) return "corinthians";
  if (clean.includes("internacional")) return "internacional";
  if (clean.includes("fluminense")) return "fluminense";
  if (clean.includes("flamengo")) return "flamengo";
  if (clean.includes("palmeiras")) return "palmeiras";
  if (clean.includes("botafogo")) return "botafogo";
  if (clean.includes("coritiba")) return "coritiba";
  if (clean.includes("cruzeiro")) return "cruzeiro";
  if (clean.includes("mirassol")) return "mirassol";
  if (clean.includes("santos")) return "santos";
  if (clean.includes("bahia")) return "bahia";
  if (clean.includes("vasco")) return "vasco";
  if (clean.includes("remo")) return "remo";
  return clean;
}

function teamIcon(name) {
  const image = TEAM_IMAGES[teamKey(name)];
  return image
    ? `<img class="team-icon" style="width:25px;height:25px;object-fit:contain;vertical-align:middle;margin:0 7px" src="${image}" alt="">`
    : "";
}
